begin;
create temporary table mindforge_seed(slug text,title text,body text,theme text,level smallint,structure text,concept text,answer text) on commit drop;

select p.id,1,s.title,s.body,'pt-BR',s.theme,array_length(regexp_split_to_array(trim(s.body),'\s+'),1),least(.95,.12+s.level*.15),least(.95,.1+s.level*.16),s.level,'nenhum conhecimento especializado',s.structure,greatest(1,ceil(array_length(regexp_split_to_array(trim(s.body),'\s+'),1)/180.0)::smallint),jsonb_build_array(s.concept),'original','Equipe MindForge — conteúdo seed original'
from mindforge_seed s join public.passages p on p.slug=s.slug on conflict(passage_id,version) do nothing;

select pv.id,case when s.level<=2 then 'main_idea' when s.level<=4 then 'inference' else 'application' end,'Qual afirmação representa melhor a ideia central?',1.5,'A alternativa correta preserva a relação central do texto.',1 from mindforge_seed s join public.passages p on p.slug=s.slug join public.passage_versions pv on pv.passage_id=p.id and pv.version=1 where not exists(select 1 from public.questions q where q.passage_version_id=pv.id);
select q.id,s.answer,true,'Você preservou a relação central.',1 from mindforge_seed s join public.passages p on p.slug=s.slug join public.passage_versions pv on pv.passage_id=p.id join public.questions q on q.passage_version_id=pv.id
union all select q.id,'O texto defende aumentar a velocidade em qualquer situação.',false,'O texto não faz promessa universal de velocidade.',2 from mindforge_seed s join public.passages p on p.slug=s.slug join public.passage_versions pv on pv.passage_id=p.id join public.questions q on q.passage_version_id=pv.id;
select pv.id,s.slug||'-central',s.concept,array[s.concept],array[s.answer],1,true from mindforge_seed s join public.passages p on p.slug=s.slug join public.passage_versions pv on pv.passage_id=p.id on conflict do nothing;
commit;
